class Solution:
    def tilingRectangle(self, n: int, m: int) -> int:
        if n > m:
            n, m = m, n
        if n == m:
            return 1
        best = [n * m]
        heights = [0] * m
        def bt(cnt):
            if cnt >= best[0]:
                return
            if all(h == n for h in heights):
                best[0] = cnt
                return
            min_h = min(heights)
            col = heights.index(min_h)
            max_sz = 1
            while col + max_sz < m and heights[col + max_sz] == min_h and min_h + max_sz < n:
                max_sz += 1
            for size in range(max_sz, 0, -1):
                for k in range(size):
                    heights[col + k] += size
                bt(cnt + 1)
                for k in range(size):
                    heights[col + k] -= size
        bt(0)
        return best[0]

solutions.javascript:
var tilingRectangle = function(n, m) {
    if (n > m) { let t = n; n = m; m = t; }
    if (n === m) return 1;
    let best = n * m;
    const heights = new Array(m).fill(0);
    function bt(cnt) {
        if (cnt >= best) return;
        if (heights.every(h => h === n)) { best = cnt; return; }
        let minH = Math.min(...heights);
        let col = heights.indexOf(minH);
        let maxSz = 1;
        while (col + maxSz < m && heights[col + maxSz] === minH && minH + maxSz < n) maxSz++;
        for (let size = maxSz; size >= 1; size--) {
            for (let k = 0; k < size; k++) heights[col + k] += size;
            bt(cnt + 1);
            for (let k = 0; k < size; k++) heights[col + k] -= size;
        }
    }
    bt(0);
    return best;
};
